declare @$deleteConflict nvarchar(512), @status char(1)
select @$deleteConflict = case when @@language = 'v' then N'Không thể xóa biểu tượng mặc định.' else N'Can not delete the default Logo.' end
select @status = status from @@table where logo_id = @logo_id
if @status = 1 begin
  select @$deleteConflict as message
  return
end






