var imgName = getFileName($get('fileupload').value), allowExt = 'gif,png,jpg,jpeg';
var err = (this._language == 'v' ? 'Định dạng tệp ảnh không đúng.' : 'Invalid file type.');
if (imgName != '') {
  var ext = imgName.split('.').pop()
  if (allowExt.indexOf(ext.toLowerCase()) < 0) {
    this._checked = false;
    $message.show(err);
  }
  else {
    this.getItem('filename').value = this._fid + '.' + ext;
    var query = '?t=' + '&UploadTyle;' + '&u=' + this._userID + '&k=' + this._key + '&f=' + this._fid + '&d=' + this._db;
    $get('uploadForm').action = '../AppHandler/FileUpload.ashx' + query
    $get('uploadForm').submit();
  }
}








function active$FormUpload(f) {
  document.body._form = f;
  $get('fileupload').value = '';  
  $get('fileupload').disabled = (f._action == 'View');
  f.getItem('upload').field.AllowNulls = (f._action == 'Edit');
  $get(f.get_id() + '_form_upload').style.color = 'grey';  
}
function close$FormUpload(f) {document.body._form = null;}
function setFileName() {
  var f = document.body._form;
  $get(f.get_id() + '_form_upload').value = getFileName($get('fileupload').value);  
}
function setButtonBehavior(e) {var f = document.body._form;
  if ((f._action != 'View')&&((e.keyCode == 13)||(e.keyCode == 32))) {$get('fileupload').click();}
}
function getFileName(s) {
  var p = s.lastIndexOf('\\');
  if (p != -1) {return s.substring(p + 1);}
  else {return s;}
}




